import{_ as s,c as o,o as a,ag as t}from"./chunks/framework.B-XtCDNB.js";const y=JSON.parse('{"title":"3.4. Symbol Resolution","description":"","frontmatter":{},"headers":[],"relativePath":"contributor-guide/compiler-guide/03-00-the-vala-compiler/03-04-symbol-resolution.md","filePath":"contributor-guide/compiler-guide/03-00-the-vala-compiler/03-04-symbol-resolution.md","lastUpdated":1776620988000}'),i={name:"contributor-guide/compiler-guide/03-00-the-vala-compiler/03-04-symbol-resolution.md"};function l(n,e,c,r,d,p){return a(),o("div",null,[...e[0]||(e[0]=[t(`<h1 id="_3-4-symbol-resolution" tabindex="-1">3.4. Symbol Resolution <a class="header-anchor" href="#_3-4-symbol-resolution" aria-label="Permalink to &quot;3.4. Symbol Resolution&quot;">​</a></h1><p><code>Vala.SymbolResolver</code> is a <code>CodeVisitor</code> that exchanges <code>Vala.UnresolvedType</code> nodes in the parse tree with <code>Vala.DataType</code> nodes and links <code>Vala.NamespaceReference</code> nodes with the correct namespace symbol. Additionally, it checks base types for classes so that classes don&#39;t inherit from multiple classes or themselves, and likewise it checks that interfaces don&#39;t need to implement themselves.</p><h2 id="_3-4-1-data-types" tabindex="-1">3.4.1. Data Types <a class="header-anchor" href="#_3-4-1-data-types" aria-label="Permalink to &quot;3.4.1. Data Types&quot;">​</a></h2><p>Every expression has a static type. This is computed by the semantic analyzer. <code>Vala.DataType</code> is called a &quot;type reference&quot; because it contains a reference to a <code>Vala.TypeSymbol</code> (a class, interface, etc.) as well as information about the expression&#39;s type, e.g., if it can be null, or, if it&#39;s an out parameter.</p><div class="info custom-block"><p class="custom-block-title">TODO</p><p>expand this section</p></div><h2 id="_3-4-2-symbols" tabindex="-1">3.4.2. Symbols <a class="header-anchor" href="#_3-4-2-symbols" aria-label="Permalink to &quot;3.4.2. Symbols&quot;">​</a></h2><p>A <code>Vala.Symbol</code> is a specialization of <code>Vala.CodeNode</code>. All symbols except for the root symbol are contained within another&#39;s scope. Types have scope and variables have scope. For types and variables, scope determines their accessibility, subject to access modifiers. For variables, scope also determines their lifetime. As the code tree is traversed, <code>SymbolResolver</code> keeps track of the current scope. For example, when a class is visited, <code>current_scope</code> is set to that class&#39;s scope.</p><p>When the parser parses a type, e.g., in the statement <code>Gtk.Window main_window</code>, the type <code>Gtk.Window</code> is initially a <code>Vala.UnresolvedType</code>. In <code>visit_data_type ()</code>, the <code>UnresolvedType</code> code node asks its parent to replace it with a new <code>Vala.DataType</code> created with <code>resolve_type ()</code>.</p><p><code>UnresolvedType</code> nodes have <code>UnresolvedSymbol</code> children. <code>resolve_type ()</code> uses <code>resolve_symbol ()</code> to find the <code>TypeSymbol</code> referred to, and then wraps it in a new <code>DataType</code> object.</p><p><code>resolve_symbol ()</code> is a recursive method which looks up an unresolved symbol&#39;s name in the current scope and returns the corresponding <code>TypeSymbol</code>. The base case is when the <code>UnresolvedSymbol</code> has no qualifiers, e.g. <code>Window</code>. The recursive case is when the symbol looks like <code>Gtk.Window</code> or <code>Gtk.Orientation.HORIZONTAL</code>. In <code>Vala.Parser.parse_symbol_name ()</code>, the symbol is built inside-out, so <code>Gtk.Orientation.HORIZONTAL</code> is parsed as:</p><div class="language-vala vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vala</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">UnresolvedSymbol</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">UnresolvedSymbol</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">UnresolvedSymbol</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">null</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Gtk&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">         &quot;Orientation&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     &quot;HORIZONTAL&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>This is inside-out because Orientation is the parent scope of HORIZONTAL, but Orientation is the child node of HORIZONTAL.</p><p>In the base case, the symbol&#39;s name is looked up in <code>current_scope</code>. If the symbol is not found there, then the scope of all imported namespaces is searched. If more than one imported namespace contains the symbol, an &quot;ambiguous reference&quot; error will be reported.</p><p>In the recursive case, <code>resolve_symbol ()</code> is called on the child node to give a parent scope, in which the symbol is looked up.</p><p>One last function of <code>SymbolResolver</code> is in <code>visit_variable_declarator ()</code> — to mark a variable type reference as &quot;nullable&quot; if the variable&#39;s type is a class, interface, array or error (reference type). This is used later by <code>Vala.NullChecker</code>.</p>`,15)])])}const m=s(i,[["render",l]]);export{y as __pageData,m as default};
